*, *::before, *::after { margin:0; padding:0; box-sizing:border-box; } body { font-family:'Manrope',system-ui,sans-serif; }

/* ============================================
       DESIGN TOKENS
       ============================================ */
    :root {
      /* Layout */
      --content-width: 615px;
      --content-padding: 48px;
      --content-gap: 32px;
      --header-title-gap: 16px;
      --title-content-gap: 64px;
      --title-max-width: 720px;

      --sidebar-drawer-width: 280px;

      /* Colors (placeholder — will map to real DS tokens) */
      --bg-page: hsl(0 0% 100%);
      --bg-header: hsl(0 0% 100%);
      --bg-title: hsl(225 40% 96%);
      --bg-sidebar-left: hsl(30 15% 93%);
      --bg-sidebar-right: hsl(225 50% 94%);
      --bg-content: hsl(0 0% 94%);
      --bg-footer: hsl(228 54% 20%);
      --border-light: hsl(0 0% 88%);
      --text-primary: hsl(228 54% 20%);
      --text-inverse: hsl(0 0% 100%);
      --text-zone-label: hsl(0 0% 50%);

      /* Sidebar triggers */
      --trigger-size: 44px;
      --trigger-offset: 12px;
      --trigger-bg: hsl(228 54% 20%);
      --trigger-color: hsl(0 0% 100%);

      /* Transitions */
      --transition-sidebar: transform 0.3s ease;
    }

    /* ============================================
       RESET & BASE
       ============================================ */
    *, *::before, *::after {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      font-family: var(--font-family-body);
      background: var(--bg-page);
      color: var(--text-primary);
      min-height: 100vh;
      overflow-x: hidden;
    }

    /* ============================================
       DEBUG SLOT VISUALIZATION
       Toggle: add/remove class "debug-slots" on <body>
       Without this class, all zones are transparent/clean.
       ============================================ */
    .debug-slots [data-slot]::after {
      content: "slot:" attr(data-slot);
      display: flex;
      align-items: center;
      justify-content: center;
      width: 100%;
      height: 100%;
      color: var(--text-zone-label);
      font-size: 14px;
      font-weight: 600;
      letter-spacing: 0.5px;
      text-transform: uppercase;
      opacity: 0.6;
      pointer-events: none;
    }

    /* ============================================
       SLOT: HEADER
       ============================================ */
    [data-slot="header"] {
      position: sticky;
      top: 0;
      z-index: 100;
    }

    /* ============================================
       META: TITLE AREA
       ============================================ */
    .theme-hero {
      width: 100%;
      margin-top: var(--header-title-gap, 16px);
    }

    .theme-title {
      display: block;
      max-width: 680px;
      margin-left: auto;
      margin-right: auto;
      font-size: var(--h1-font-size);
      line-height: var(--h1-line-height);
      font-weight: var(--font-weight-regular);
      letter-spacing: var(--h1-letter-spacing);
      text-align: center;
      padding: var(--spacing-xl, 48px) var(--spacing-md, 16px);
    }

    .theme-divider {
      width: 100%;
      margin-top: var(--spacing-5xl, 64px);
      border-top: 1px solid hsl(var(--brand-biege, 30 19% 90%));
    }

    /* ============================================
       MAIN 3-COLUMN LAYOUT
       ============================================ */
    .theme-layout {
      display: grid;
      grid-template-columns: 1fr calc(var(--content-width) + var(--content-padding) * 2) 1fr;
      min-height: 80vh;
      transition: var(--transition-sidebar);
    }

    .theme-layout-frame {
      width: 100%;
      padding-top: var(--spacing-4xl, 48px);
    }

    /* ============================================
       SLOT: SIDEBAR LEFT
       ============================================ */
    [data-slot="sidebar-left"] {
      display: flex;
      align-items: flex-start;
      justify-content: center;
      min-height: 400px;
    }

    /* ============================================
       SLOT: CONTENT
       ============================================ */
    [data-slot="content"] {
      padding: 0 var(--content-padding);
      min-height: 600px;
      display: flex;
      flex-direction: column;
      gap: var(--content-gap);
    }

    /* ============================================
       SLOT: SIDEBAR RIGHT
       ============================================ */
    [data-slot="sidebar-right"] {
      display: flex;
      align-items: flex-start;
      justify-content: center;
      min-height: 400px;
    }

    /* ============================================
       SLOT: FOOTER
       ============================================ */
    [data-slot="footer"] {
      min-height: 120px;
      margin-top: var(--spacing-2xl);
    }

    /* ============================================
       DEBUG: SLOT COLORS (only with .debug-slots on body)
       ============================================ */
    .debug-slots [data-slot="header"] {
      background: var(--bg-header);
      border-bottom: 1px solid var(--border-light);
    }
    .debug-slots .theme-title {
      background: var(--bg-title);
    }

    .debug-slots [data-slot="sidebar-left"] {
      background: var(--bg-sidebar-left);
    }
    .debug-slots [data-slot="content"] {
      background: var(--bg-content);
    }
    .debug-slots [data-slot="content"]::after {
      align-items: flex-start;
      padding-top: var(--spacing-xl);
    }
    .debug-slots [data-slot="sidebar-right"] {
      background: var(--bg-sidebar-right);
    }
    .debug-slots [data-slot="footer"] {
      background: var(--bg-footer);
    }
    .debug-slots [data-slot="footer"]::after {
      color: var(--text-inverse);
    }

    /* ============================================
       SIDEBAR TRIGGERS (hidden on desktop)
       ============================================ */
    .sidebar-trigger {
      display: none;
      position: fixed;
      top: 50%;
      transform: translateY(-50%);
      width: var(--trigger-size);
      height: var(--trigger-size);
      background: var(--trigger-bg);
      color: var(--trigger-color);
      border: none;
      border-radius: 8px;
      cursor: pointer;
      z-index: 200;
      align-items: center;
      justify-content: center;
      font-size: 18px;
      box-shadow: 0 2px 8px hsl(0 0% 0% / 0.15);
    }

    .sidebar-trigger--left {
      left: var(--trigger-offset);
    }

    .sidebar-trigger--right {
      right: var(--trigger-offset);
    }

    /* ============================================
       RESPONSIVE — TABLET & MOBILE (<1400px)
       ============================================ */
    @media (max-width: 1400px) {
      .theme-layout {
        grid-template-columns: 1fr;
        max-width: calc(var(--content-width) + var(--content-padding) * 2);
        margin-left: auto;
        margin-right: auto;
      }

      /* Sidebars become fixed drawers */
      [data-slot="sidebar-left"],
      [data-slot="sidebar-right"] {
        position: fixed;
        top: var(--header-height);
        bottom: 0;
        width: var(--sidebar-drawer-width);
        z-index: 150;
        background: var(--bg-header);
        overflow-y: auto;
        box-shadow: 2px 0 12px hsl(0 0% 0% / 0.1);
        min-height: unset;
      }

      [data-slot="sidebar-left"] {
        left: 0;
        transform: translateX(-100%);
        transition: var(--transition-sidebar);
      }

      [data-slot="sidebar-right"] {
        right: 0;
        transform: translateX(100%);
        transition: var(--transition-sidebar);
      }

      /* Open states */
      [data-slot="sidebar-left"].is-open {
        transform: translateX(0);
      }

      [data-slot="sidebar-right"].is-open {
        transform: translateX(0);
      }

      /* Push content */
      .theme-layout.push-left {
        transform: translateX(var(--sidebar-drawer-width));
      }

      .theme-layout.push-right {
        transform: translateX(calc(var(--sidebar-drawer-width) * -1));
      }

      /* Show triggers */
      .sidebar-trigger {
        display: flex;
      }

      /* Content full-width */
      [data-slot="content"] {
        padding: 0 var(--spacing-lg);
      }
    }

    /* ============================================
       RESPONSIVE — MOBILE (<768px)
       ============================================ */
    @media (max-width: 768px) {
      [data-slot="header"] {
        height: 56px;
      }

      .theme-title {
        font-size: 36px;
        line-height: 44px;
        max-width: 100%;
      }

      .theme-layout {
        margin-top: 0;
      }

      [data-slot="content"] {
        padding: 0 var(--spacing-sm);
        min-height: 400px;
      }

      [data-slot="sidebar-left"],
      [data-slot="sidebar-right"] {
        width: 260px;
      }

      .theme-layout.push-left {
        transform: translateX(260px);
      }

      .theme-layout.push-right {
        transform: translateX(-260px);
      }
    }
